import React, { useRef } from "react";

/**
 * Componente TicketVenta
 * Renderiza una vista previa del ticket y permite su impresión física.
 */
export default function TicketVenta({ ticket, setTicket }) {
  const ticketRef = useRef(null);

  const imprimirTicket = () => {
    if (!ticketRef.current) return;

    // Abrimos una ventana nueva para la impresión
    const ventana = window.open("", "PRINT", "width=400,height=600");
    
    ventana.document.write(`
      <html>
        <head>
          <title>Ticket de Venta - PosSystem</title>
          <style>
            @page { size: auto; margin: 0mm; }
            body {
              font-family: 'Courier New', Courier, monospace;
              font-size: 12px;
              padding: 20px;
              width: 300px;
            }
            .text-center { text-align: center; }
            .fw-bold { font-weight: bold; }
            hr { border: 1px dashed #000; margin: 10px 0; }
            table { width: 100%; border-collapse: collapse; }
            th { border-bottom: 1px solid #000; text-align: left; }
            td { padding: 5px 0; }
            .flex { display: flex; justify-content: space-between; }
            .mt-2 { margin-top: 10px; }
            /* Ocultar botones en la impresión */
            .no-print { display: none; }
          </style>
        </head>
        <body>
          <div class="text-center">
            <h4>🧾 TICKET DE VENTA</h4>
            <p>${ticket.EmisorNombre || "NOMBRE DE TU EMPRESA"}</p>
          </div>
          <hr />
          <p><strong>Cliente:</strong> ${ticket.NombreCliente || "Consumidor Final"}</p>
          <p><strong>Fecha:</strong> ${new Date(ticket.Fecha).toLocaleString()}</p>
          <p><strong>No. Venta:</strong> ${ticket.NumeroSecuencia || ticket._id.substring(0,8)}</p>
          <hr />
          <table>
            <thead>
              <tr>
                <th>Prod.</th>
                <th>Cant.</th>
                <th>Subt.</th>
              </tr>
            </thead>
            <tbody>
              ${ticket.productos.map(p => `
                <tr>
                  <td>${p.Nombre}</td>
                  <td>${p.Cantidad}</td>
                  <td>$${Number(p.Subtotal).toFixed(2)}</td>
                </tr>
              `).join('')}
            </tbody>
          </table>
          <hr />
          <div class="flex"><span>Subtotal:</span> <span>$${Number(ticket.Subtotal).toFixed(2)}</span></div>
          <div class="flex"><span>IVA (13%):</span> <span>$${Number(ticket.IVA).toFixed(2)}</span></div>
          <div class="flex fw-bold mt-2"><span>TOTAL:</span> <span>$${Number(ticket.Total).toFixed(2)}</span></div>
          <hr />
          <p class="text-center">¡Gracias por su compra!</p>
        </body>
      </html>
    `);

    ventana.document.close();
    ventana.focus();
    // Pequeño delay para asegurar que el contenido cargue antes de imprimir
    setTimeout(() => {
      ventana.print();
      ventana.close();
    }, 250);
  };

  if (!ticket) return null;

  return (
    <div className="card mt-4 p-4 shadow-lg border-0" style={{ width: "380px", margin: "0 auto", backgroundColor: "#fff" }}>
      <div ref={ticketRef}>
        <div className="text-center">
          <h5 className="fw-bold mb-1">🧾 TICKET DE VENTA</h5>
          <p className="text-muted small">{ticket.EmisorNombre || "Empresa de San Alejo"}</p>
        </div>
        
        <div className="small mt-3">
          <div className="d-flex justify-content-between">
            <span className="fw-bold">Cliente:</span>
            <span>{ticket.NombreCliente}</span>
          </div>
          <div className="d-flex justify-content-between">
            <span className="fw-bold">Fecha:</span>
            <span>{new Date(ticket.Fecha).toLocaleDateString()}</span>
          </div>
          <div className="d-flex justify-content-between">
            <span className="fw-bold">No. Venta:</span>
            <span className="text-primary">{ticket.NumeroSecuencia || "S/N"}</span>
          </div>
        </div>

        <hr className="my-3" style={{ borderTop: "1px dashed #ccc" }} />

        <table className="table table-sm table-borderless small">
          <thead>
            <tr className="border-bottom">
              <th>Producto</th>
              <th className="text-center">Cant</th>
              <th className="text-end">Subt</th>
            </tr>
          </thead>
          <tbody>
            {ticket.productos.map((p, idx) => (
              <tr key={idx}>
                <td>{p.Nombre}</td>
                <td className="text-center">{p.Cantidad}</td>
                <td className="text-end">${Number(p.Subtotal).toFixed(2)}</td>
              </tr>
            ))}
          </tbody>
        </table>

        <hr className="my-3" style={{ borderTop: "1px dashed #ccc" }} />

        <div className="small">
          <div className="d-flex justify-content-between">
            <span>Subtotal:</span>
            <span>${Number(ticket.Subtotal).toFixed(2)}</span>
          </div>
          <div className="d-flex justify-content-between">
            <span>IVA:</span>
            <span>${Number(ticket.IVA).toFixed(2)}</span>
          </div>
          <div className="d-flex justify-content-between fw-bold fs-6 mt-2">
            <span>TOTAL:</span>
            <span className="text-success">${Number(ticket.Total).toFixed(2)}</span>
          </div>
        </div>
      </div>

      <div className="d-flex gap-2 mt-4">
        <button className="btn btn-primary w-100 fw-bold" onClick={imprimirTicket}>
          🖨 Imprimir Ticket
        </button>
        <button className="btn btn-light w-100 border" onClick={() => setTicket(null)}>
          Cerrar
        </button>
      </div>
    </div>
  );
}
